MT.tag:
function getTagValue(docSwift, tagCodeName){
	var swiftContent = docSwift.documentElement;
	var children = swiftContent.childNodes;
	for (var i = 0; i < children.length; i++) {
		var child = children.item(i);
		if (child.nodeType == 1) {
			if(child.nodeName == 'trx-data'){
				var tags = child.childNodes;
				for (var j = 0; j < tags.length; j++) {
					var tag = tags.item(j);
					if (tag.nodeType == 1) {
						if(tag.nodeName == 'tag'){
							var tagCode = tag.getAttribute('tagcode');
							if(tagCode == tagCodeName){
								var tagValueNode = tag.getElementsByTagName('tag-value').item(0);
								var tagValue = tagValueNode.firstChild.textContent;
								return tagValue;
							}
						}
					}
				}
			}
		}
	}
}
var tagValue = getTagValue(docSwift, '71A');
var isSkip = true;
if(tagValue == 'BEN'){
	isSkip = false;
} else if(tagValue == 'SHA'){
	isSkip = true;
} else if(tagValue == 'OUR'){
	isSkip = true;
}
